#include <pthread.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    int id;
    const char *message;
} thread_arg_t;

void *worker(void *arg) {
    thread_arg_t *ta = (thread_arg_t *)arg;
    printf("Thread %d: %s\n", ta->id, ta->message);

    /* Allocate and return a result */
    int *result = malloc(sizeof(int));
    *result = ta->id * 10;
    return result;
}

int main(void) {
    pthread_t threads[3];
    thread_arg_t args[3] = {
        {1, "Hello"}, {2, "World"}, {3, "!"}
    };

    /* Create threads */
    for (int i = 0; i < 3; i++) {
        int ret = pthread_create(&threads[i], NULL, worker, &args[i]);
        if (ret != 0) {
            fprintf(stderr, "pthread_create: %s\n", strerror(ret));
            return 1;
        }
    }

    /* Join threads and get results */
    for (int i = 0; i < 3; i++) {
        void *retval;
        pthread_join(threads[i], &retval);
        printf("Thread %d returned: %d\n", i + 1, *(int *)retval);
        free(retval);
    }

    return 0;
}

