typedef struct {
    int thread_id;
    int call_count;
} thread_data_t;

thread_data_t *get_thread_data(void) {
    /* Initialize key once (thread-safe) */
    pthread_once(&key_once, init_key);

    thread_data_t *data = pthread_getspecific(tsd_key);
    if (data == NULL) {
        /* First call in this thread -- allocate */
        data = calloc(1, sizeof(thread_data_t));
        pthread_setspecific(tsd_key, data);
    }
    return data;
}

