#include <string.h>
#include <stdio.h>
#include <pthread.h>

/* NOT thread-safe: static internal state */
void demo_strtok(const char *input) {
    char buf[128];
    strncpy(buf, input, sizeof(buf) - 1);
    buf[sizeof(buf) - 1] = '\0';
    char *token = strtok(buf, " ");
    while (token) {
        printf("%s\n", token);
        token = strtok(NULL, " ");
    }
}

/* Thread-safe AND reentrant: explicit state */
void demo_strtok_r(const char *input) {
    char buf[128];
    strncpy(buf, input, sizeof(buf) - 1);
    buf[sizeof(buf) - 1] = '\0';
    char *saveptr;  /* caller provides state */
    char *token = strtok_r(buf, " ", &saveptr);
    while (token) {
        printf("%s\n", token);
        token = strtok_r(NULL, " ", &saveptr);
    }
}

