Without atomics (data race):
  counter++  ->  temp = counter; temp++; counter = temp;
  // Two threads can read same value -> lost update

With atomics (no data race):
  atomic_fetch_add(&counter, 1)
  // Single hardware instruction, no race possible

CAS (compare and swap):
  expected = atomic_load(&var);
  desired = expected + 1;
  atomic_compare_exchange_strong(&var, &expected, desired);
  // Sets var=desired only if var==expected, atomically

