#include <stdio.h>

#define NTHREADS 10
#define ITERATIONS 1000000

static atomic_int counter = 0;

void *increment(void *arg) {
    (void)arg;
    for (int i = 0; i < ITERATIONS; i++)
        atomic_fetch_add(&counter, 1);  /* lock-free, no mutex */
    return NULL;
