/* Spinlock using atomic_flag */
static atomic_flag spinlock = ATOMIC_FLAG_INIT;
static int protected_data = 0;

void spin_lock(atomic_flag *lock) {
    while (atomic_flag_test_and_set(lock))  /* returns old value */
        ;  /* spin */
}

void spin_unlock(atomic_flag *lock) {
    atomic_flag_clear(lock);
}

void *spin_worker(void *arg) {
    (void)arg;
    for (int i = 0; i < 100000; i++) {
        spin_lock(&spinlock);
        protected_data++;
        spin_unlock(&spinlock);
    }
    return NULL;
}

