           atomic_load(&counter), NTHREADS * ITERATIONS);

    /* Spinlock example */
    for (int i = 0; i < NTHREADS; i++)
        pthread_create(&threads[i], NULL, spin_worker, NULL);
    for (int i = 0; i < NTHREADS; i++)
        pthread_join(threads[i], NULL);
    printf("Spinlock data: %d (expected %d)\n",
           protected_data, NTHREADS * 100000);

    return 0;
}

