#include <pthread.h>
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

typedef struct task {
    void (*function)(void *arg);
    void *arg;
    struct task *next;
} task_t;

typedef struct {
    pthread_t *threads;
    int thread_count;
    task_t *queue_head;
    task_t *queue_tail;
    pthread_mutex_t mutex;
    pthread_cond_t not_empty;
    int shutdown;
} threadpool_t;

void *worker(void *arg) {
    threadpool_t *pool = (threadpool_t *)arg;
    for (;;) {
        pthread_mutex_lock(&pool->mutex);
        while (pool->queue_head == NULL && !pool->shutdown)
            pthread_cond_wait(&pool->not_empty, &pool->mutex);

        if (pool->shutdown && pool->queue_head == NULL) {
            pthread_mutex_unlock(&pool->mutex);
            return NULL;
        }

        task_t *task = pool->queue_head;
        pool->queue_head = task->next;
        if (pool->queue_head == NULL) pool->queue_tail = NULL;
        pthread_mutex_unlock(&pool->mutex);

        task->function(task->arg);
        free(task);
    }
}

threadpool_t *threadpool_create(int num_threads) {
    threadpool_t *pool = calloc(1, sizeof(threadpool_t));
    pool->thread_count = num_threads;
    pool->threads = malloc(sizeof(pthread_t) * (size_t)num_threads);
    pthread_mutex_init(&pool->mutex, NULL);
    pthread_cond_init(&pool->not_empty, NULL);
    for (int i = 0; i < num_threads; i++)
        pthread_create(&pool->threads[i], NULL, worker, pool);
    return pool;
}

void threadpool_submit(threadpool_t *pool, void (*fn)(void*), void *arg) {
    task_t *task = malloc(sizeof(task_t));
    task->function = fn;
    task->arg = arg;
    task->next = NULL;
    pthread_mutex_lock(&pool->mutex);
    if (pool->queue_tail)
        pool->queue_tail->next = task;
    else
        pool->queue_head = task;
    pool->queue_tail = task;
    pthread_cond_signal(&pool->not_empty);
    pthread_mutex_unlock(&pool->mutex);
}

void threadpool_destroy(threadpool_t *pool) {
    pthread_mutex_lock(&pool->mutex);
    pool->shutdown = 1;
    pthread_cond_broadcast(&pool->not_empty);
    pthread_mutex_unlock(&pool->mutex);
    for (int i = 0; i < pool->thread_count; i++)
        pthread_join(pool->threads[i], NULL);
    free(pool->threads);
    pthread_mutex_destroy(&pool->mutex);
    pthread_cond_destroy(&pool->not_empty);
    free(pool);
}

/* Example task */
void print_task(void *arg) {
    int n = *(int *)arg;
    printf("Task %d on thread %lu\n", n, (unsigned long)pthread_self());
    free(arg);
}

int main(void) {
    threadpool_t *pool = threadpool_create(4);
    for (int i = 0; i < 20; i++) {
        int *n = malloc(sizeof(int));
        *n = i;
        threadpool_submit(pool, print_task, n);
    }
    sleep(1);
    threadpool_destroy(pool);
    return 0;
}

