#include <pthread.h>
#include <stdio.h>

/* Problem: Print 1-20 alternating between two threads */
static int number = 1;
static int turn = 1;  /* 1 = odd's turn, 2 = even's turn */
static pthread_mutex_t mtx = PTHREAD_MUTEX_INITIALIZER;
static pthread_cond_t cond = PTHREAD_COND_INITIALIZER;

void *print_odd(void *arg) {
    (void)arg;
    while (1) {
        pthread_mutex_lock(&mtx);
        while (turn != 1 && number <= 20)
            pthread_cond_wait(&cond, &mtx);
        if (number > 20) {
            pthread_mutex_unlock(&mtx);
            break;
        }
        printf("Odd thread:  %d\n", number++);
        turn = 2;
        pthread_cond_signal(&cond);
        pthread_mutex_unlock(&mtx);
    }
    return NULL;
}

void *print_even(void *arg) {
    (void)arg;
    while (1) {
        pthread_mutex_lock(&mtx);
        while (turn != 2 && number <= 20)
            pthread_cond_wait(&cond, &mtx);
        if (number > 20) {
            pthread_mutex_unlock(&mtx);
            break;
        }
        printf("Even thread: %d\n", number++);
        turn = 1;
        pthread_cond_signal(&cond);
        pthread_mutex_unlock(&mtx);
    }
    return NULL;
}

int main(void) {
    pthread_t t1, t2;
    pthread_create(&t1, NULL, print_odd, NULL);
    pthread_create(&t2, NULL, print_even, NULL);
    pthread_join(t1, NULL);
    pthread_join(t2, NULL);
    printf("Done: printed 1-20 alternating\n");
    return 0;
}

